'use client';

import { useState } from 'react';
import type { Transaction } from '@/types';
import { StatusBadge } from '@/components/ui/StatusBadge';
import { formatCurrency, formatFullDate, formatRelativeTime, getInitials } from '@/lib/formatters';

interface TransactionCardProps {
  transaction: Transaction;
}

export function TransactionCard({ transaction }: TransactionCardProps) {
  const [expanded, setExpanded] = useState(false);

  const {
    recipientName, recipientBank, recipientAccount,
    senderAmount, senderCurrency,
    receiverAmount, receiverCurrency,
    exchangeRate, status, createdAt,
    narration, failureReason, txHash,
  } = transaction;

  const initials = getInitials(recipientName);
  const hue = recipientName.split('').reduce((acc, c) => acc + c.charCodeAt(0), 0) % 360;

  return (
    <div className={[
      'rounded-xl border bg-[#0f0f1a] transition-all duration-150',
      expanded ? 'border-[#2a2a45]' : 'border-[#1e1e32] hover:border-[#242438]',
    ].join(' ')}>

      {/* Main row */}
      <button
        type="button"
        onClick={() => setExpanded((p) => !p)}
        className="w-full flex items-center gap-4 px-4 py-4 text-left"
      >
        {/* Avatar */}
        <div
          className="flex h-10 w-10 flex-shrink-0 items-center justify-center rounded-full text-[11px] font-bold"
          style={{
            background: `hsl(${hue} 60% 15%)`,
            color:      `hsl(${hue} 80% 70%)`,
            border:     `1px solid hsl(${hue} 60% 22%)`,
          }}
        >
          {initials}
        </div>

        {/* Info */}
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 flex-wrap">
            <p className="text-sm font-medium text-zinc-200 truncate">{recipientName}</p>
            {narration && (
              <span className="text-[10.5px] text-zinc-600 truncate hidden sm:block">· {narration}</span>
            )}
          </div>
          <div className="mt-1 flex items-center gap-2 flex-wrap">
            <StatusBadge status={status} />
            <span className="text-[11px] text-zinc-700">{formatRelativeTime(createdAt)}</span>
          </div>
        </div>

        {/* Amount */}
        <div className="flex-shrink-0 text-right">
          <p className="text-sm font-mono font-semibold text-red-400">
            -{formatCurrency(senderAmount, senderCurrency)}
          </p>
          <p className="mt-0.5 text-[10.5px] font-mono text-zinc-600">
            ≈ {formatCurrency(receiverAmount, receiverCurrency)}
          </p>
        </div>

        {/* Chevron */}
        <svg
          className={`flex-shrink-0 text-zinc-700 transition-transform duration-200 ${expanded ? 'rotate-180' : ''}`}
          width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
        >
          <polyline points="6 9 12 15 18 9"/>
        </svg>
      </button>

      {/* Expanded detail */}
      {expanded && (
        <div className="border-t border-[#1a1a2e] px-4 py-4">
          <div className="grid grid-cols-2 gap-x-6 gap-y-3 text-[12.5px]">
            {[
              { label: 'Bank / Wallet',  value: recipientBank },
              { label: 'Account',        value: recipientAccount },
              { label: 'Date',           value: formatFullDate(createdAt) },
              { label: 'Exchange rate',  value: `1 GHS = ₦${exchangeRate.toFixed(2)}`, mono: true },
              { label: 'You sent',       value: formatCurrency(senderAmount, senderCurrency), mono: true },
              { label: 'They received',  value: formatCurrency(receiverAmount, receiverCurrency), mono: true, green: true },
            ].map((row) => (
              <div key={row.label}>
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">{row.label}</p>
                <p className={[
                  'mt-0.5',
                  row.mono  ? 'font-mono' : '',
                  row.green ? 'text-emerald-400' : 'text-zinc-300',
                ].join(' ')}>
                  {row.value}
                </p>
              </div>
            ))}

            {narration && (
              <div className="col-span-2">
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">Narration</p>
                <p className="mt-0.5 text-zinc-300">{narration}</p>
              </div>
            )}

            {txHash && (
              <div className="col-span-2">
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">Tx hash</p>
                <p className="mt-0.5 font-mono text-[11px] text-indigo-400 break-all">{txHash}</p>
              </div>
            )}

            {failureReason && (
              <div className="col-span-2">
                <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">Failure reason</p>
                <p className="mt-0.5 text-red-400 text-[12px]">{failureReason}</p>
              </div>
            )}
          </div>

          {/* Retry button for failed */}
          {status === 'FAILED' && (
            <div className="mt-4 pt-3 border-t border-[#1a1a2e]">
              <button
                type="button"
                className="flex items-center gap-2 rounded-lg border border-indigo-500/30 bg-indigo-600/10 px-3 py-2 text-[12px] font-medium text-indigo-400 hover:bg-indigo-600/20 transition-all"
              >
                <svg width="12" height="12" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
                  <polyline points="1 4 1 10 7 10"/>
                  <path d="M3.51 15a9 9 0 1 0 .49-3.68"/>
                </svg>
                Retry transfer
              </button>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
