import type { Transaction } from '@/types';
import { formatCurrency } from '@/lib/formatters';

interface TransactionStatsProps {
  transactions: Transaction[];
}

export function TransactionStats({ transactions }: TransactionStatsProps) {
  const completed = transactions.filter((t) => t.status === 'COMPLETED');
  const failed    = transactions.filter((t) => t.status === 'FAILED');
  const pending   = transactions.filter((t) => !['COMPLETED', 'FAILED'].includes(t.status));

  const totalSent = completed.reduce((sum, t) => sum + t.senderAmount, 0);
  const avgRate   = completed.length
    ? completed.reduce((sum, t) => sum + t.exchangeRate, 0) / completed.length
    : 0;

  const stats = [
    { label: 'Total transfers', value: transactions.length.toString(),      sub: 'all time'         },
    { label: 'Total sent',      value: formatCurrency(totalSent, 'NGN'),    sub: `${completed.length} completed`, mono: true },
    { label: 'Avg. rate',       value: avgRate > 0 ? avgRate.toFixed(2) : '—', sub: 'NGN per GHS',  mono: true },
    { label: 'Failed',          value: failed.length.toString(),            sub: `${pending.length} pending`, red: failed.length > 0 },
  ];

  return (
    <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
      {stats.map((stat) => (
        <div key={stat.label} className="rounded-xl border border-[#1e1e32] bg-[#0f0f1a] p-4">
          <p className="text-[10px] font-semibold uppercase tracking-widest text-zinc-700">{stat.label}</p>
          <p className={[
            'mt-1.5 text-lg font-semibold leading-none',
            stat.mono ? 'font-mono' : '',
            stat.red  ? 'text-red-400' : 'text-zinc-100',
          ].join(' ')}>
            {stat.value}
          </p>
          <p className="mt-1 text-[10.5px] text-zinc-700">{stat.sub}</p>
        </div>
      ))}
    </div>
  );
}
