'use client';

import { useState, useMemo } from 'react';
import Link from 'next/link';
import { TransactionFilters } from '@/components/transactions/TransactionFilters';
import { TransactionCard } from '@/components/transactions/TransactionCard';
import { TransactionStats } from '@/components/transactions/TransactionStats';
import { MOCK_TRANSACTIONS } from '@/data/mockData';
import type { TransactionStatus, Currency } from '@/types';

export default function TransactionsPage() {
  const [statusFilter,   setStatusFilter]   = useState<TransactionStatus | 'ALL'>('ALL');
  const [currencyFilter, setCurrencyFilter] = useState<Currency | 'ALL'>('ALL');
  const [searchQuery,    setSearchQuery]    = useState('');

  const filtered = useMemo(() => {
    return MOCK_TRANSACTIONS.filter((tx) => {
      if (statusFilter !== 'ALL' && tx.status !== statusFilter) return false;
      if (currencyFilter !== 'ALL' && tx.senderCurrency !== currencyFilter) return false;
      if (searchQuery.trim()) {
        const q = searchQuery.toLowerCase();
        const matches =
          tx.recipientName.toLowerCase().includes(q)  ||
          tx.recipientBank.toLowerCase().includes(q)  ||
          (tx.narration ?? '').toLowerCase().includes(q);
        if (!matches) return false;
      }
      return true;
    });
  }, [statusFilter, currencyFilter, searchQuery]);

  return (
    <div className="min-h-screen bg-[#080812] text-zinc-100">
      {/* Top bar */}
      <header className="sticky top-0 z-30 flex h-14 items-center justify-between border-b border-[#1a1a2e] bg-[#080812]/90 px-5 backdrop-blur-sm">
        <div className="flex items-center gap-2.5">
          <div className="flex h-7 w-7 items-center justify-center rounded-lg bg-indigo-600">
            <svg width="14" height="14" viewBox="0 0 16 16" fill="none">
              <path d="M2 8h5M9 4l5 4-5 4" stroke="white" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/>
            </svg>
          </div>
          <span className="text-sm font-semibold tracking-tight text-zinc-100">
            Remitly<span className="text-indigo-400">NG</span>
          </span>
        </div>
        <Link href="/" className="flex items-center gap-1.5 text-[12.5px] text-zinc-500 hover:text-zinc-300 transition-colors">
          <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
            <line x1="19" y1="12" x2="5" y2="12"/>
            <polyline points="12 19 5 12 12 5"/>
          </svg>
          Dashboard
        </Link>
      </header>

      <main className="mx-auto max-w-3xl px-4 py-8">

        {/* Page heading */}
        <div className="mb-6 flex items-center justify-between gap-4">
          <div>
            <h1 className="text-xl font-semibold tracking-tight text-zinc-100">Transactions</h1>
            <p className="mt-1 text-sm text-zinc-600">Your full transfer history</p>
          </div>
          <Link
            href="/send"
            className="flex items-center gap-2 rounded-xl bg-indigo-600 px-4 py-2.5 text-sm font-semibold text-white hover:bg-indigo-500 transition-all shadow-lg shadow-indigo-600/20"
          >
            <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
              <line x1="22" y1="2" x2="11" y2="13"/>
              <polygon points="22 2 15 22 11 13 2 9 22 2"/>
            </svg>
            Send money
          </Link>
        </div>

        {/* Stats */}
        <div className="mb-6">
          <TransactionStats transactions={MOCK_TRANSACTIONS} />
        </div>

        {/* Filters */}
        <div className="mb-5">
          <TransactionFilters
            statusFilter={statusFilter}
            currencyFilter={currencyFilter}
            searchQuery={searchQuery}
            onStatusChange={setStatusFilter}
            onCurrencyChange={setCurrencyFilter}
            onSearchChange={setSearchQuery}
          />
        </div>

        {/* Results count */}
        <div className="mb-3 flex items-center justify-between">
          <p className="text-[12px] text-zinc-600">
            {filtered.length} {filtered.length === 1 ? 'transaction' : 'transactions'}
            {statusFilter !== 'ALL' || currencyFilter !== 'ALL' || searchQuery ? ' matching filters' : ''}
          </p>
          {(statusFilter !== 'ALL' || currencyFilter !== 'ALL' || searchQuery) && (
            <button
              type="button"
              onClick={() => { setStatusFilter('ALL'); setCurrencyFilter('ALL'); setSearchQuery(''); }}
              className="text-[12px] text-indigo-400 hover:text-indigo-300 transition-colors"
            >
              Clear filters
            </button>
          )}
        </div>

        {/* Transaction list */}
        {filtered.length > 0 ? (
          <div className="flex flex-col gap-3">
            {filtered.map((tx) => (
              <TransactionCard key={tx.id} transaction={tx} />
            ))}
          </div>
        ) : (
          <div className="flex flex-col items-center justify-center gap-3 rounded-2xl border border-[#1e1e32] bg-[#0f0f1a] py-16">
            <div className="flex h-12 w-12 items-center justify-center rounded-full border border-[#1e1e32] bg-[#0c0c1a]">
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round" className="text-zinc-700">
                <circle cx="11" cy="11" r="8"/>
                <line x1="21" y1="21" x2="16.65" y2="16.65"/>
              </svg>
            </div>
            <p className="text-sm font-medium text-zinc-500">No transactions found</p>
            <p className="text-xs text-zinc-700">Try adjusting your filters</p>
          </div>
        )}
      </main>
    </div>
  );
}
